        const x1 = 10 + Math.cos(rad) * 7;
        const y1 = 10 - Math.sin(rad) * 7;
        const x2 = 10 + Math.cos(rad) * 8;
        const y2 = 10 - Math.sin(rad) * 8;
        return (
          <line
            key={deg}
